""" Erreurs. """

from .command.status import STATUS


class Error(Exception):
    """Une erreur.

    Chaque type d'erreur est associée à un code de status et un message.
    """

    status = STATUS.FAILURE
    """ Code de status. """

    message = "erreur inconnue"
    """ Message d'erreur. """


class CommandNotFound(Exception):
    """Une erreur due à un exécutable introuvable."""

    status = STATUS.NOT_FOUND

    def __init__(self, command: str = None):
        self.message = "exécutable introuvable"

        if command:
            self.message += f": {command}"
